  `dimensions` varchar(255) DEFAULT NULL,
  `material` varchar(255) DEFAULT NULL,
  `part_name` varchar(100) NOT NULL,
  `part_number` varchar(255) DEFAULT NULL,
  `quantity_required` int DEFAULT NULL,
  `specifications` text,
  `unit_of_measure` varchar(255) DEFAULT NULL,
  `updated_at` datetime(6) DEFAULT NULL,
  `updated_by` varchar(255) DEFAULT NULL,
  `product_id` bigint NOT NULL,
  `vendor_id` bigint DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `FK6wl70delay49u63h24sxgk7ry` (`product_id`),
  KEY `FKoqpkfgv3bihpu73s784iwavuq` (`vendor_id`),
  CONSTRAINT `FK6wl70delay49u63h24sxgk7ry` FOREIGN KEY (`product_id`) REFERENCES `products` (`id`),
  CONSTRAINT `FKoqpkfgv3bihpu73s784iwavuq` FOREIGN KEY (`vendor_id`) REFERENCES `vendors` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=248 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
