INSERT INTO `products` VALUES (1,_binary '','IndustryMax',NULL,NULL,'Material Handling','2025-07-14 08:49:59.173623','system','Industrial grade conveyor belt system designed for heavy-duty material handling in manufacturing environments. Features steel frame construction with variable speed control.','3000mm x 800mm x 1200mm','Steel Frame with Rubber Belt','CBX-3000','Heavy Duty Conveyor Belt System',NULL,'Load capacity: 500kg/m, Speed: 0.1-2.0 m/s, Motor: 5.5kW, Belt width: 800mm','Sets','2025-07-14 08:49:59.173623','system',850),(2,_binary '','TechPrecision',NULL,NULL,'Machine Tools','2025-07-14 08:49:59.208213','system','High-precision 3-axis CNC milling machine with automatic tool changer. Suitable for precision machining of metal components with tight tolerances.','2200mm x 1800mm x 2400mm','Cast Iron Base with Steel Framework','VM-850','Precision CNC Vertical Milling Machine',NULL,'Spindle speed: 8000 RPM, Tool capacity: 20, Working area: 850x450x400mm, Positioning accuracy: ±0.005mm','Pieces','2025-07-14 08:49:59.208213','system',2500),(3,_binary '','PowerForge',NULL,NULL,'Forming Equipment','2025-07-14 08:49:59.208213','system','Heavy-duty hydraulic press for metal forming, stamping, and pressing operations. Features programmable pressure control and safety systems.','2500mm x 1500mm x 3500mm','Steel Frame with Hydraulic Components','HP-200T','Industrial Hydraulic Press',NULL,'Max pressure: 200 tons, Stroke: 400mm, Table size: 1200x800mm, Pump motor: 11kW','Pieces','2025-07-14 08:49:59.208213','system',3200),(4,_binary '','AirFlow',NULL,NULL,'Pneumatic Equipment','2025-07-14 08:49:59.208213','system','Energy-efficient rotary screw air compressor with variable speed drive. Designed for continuous operation in industrial environments.','1800mm x 1200mm x 1600mm','Steel Housing with Cast Iron Compressor Block','RS-75VSD','Rotary Screw Air Compressor',NULL,'Flow rate: 13.2 m³/min, Pressure: 8 bar, Motor: 75kW VSD, Noise level: <70dB','Pieces','2025-07-14 08:49:59.208213','system',1200),(5,_binary '','RoboWeld',NULL,NULL,'Automation Equipment','2025-07-14 08:49:59.224279','system','Automated welding robot with 6-axis articulation for complex welding applications. Includes welding power source and wire feeder.','1400mm reach, Base: 600mm x 600mm','Aluminum Alloy Arms with Steel Base','WR-1400','6-Axis Welding Robot System',NULL,'Payload: 6kg, Reach: 1400mm, Repeatability: ±0.08mm, Welding current: 350A','Sets','2025-07-14 14:28:23.532542','system',750),(6,_binary '','LiftMaster',NULL,NULL,'Lifting Equipment','2025-07-14 08:49:59.224279','system','Double girder overhead crane for heavy lifting applications in industrial facilities. Remote control operation with safety features.','Span: 20m, Lift height: 12m','Steel Structure with Wire Rope Hoist','BOC-20T','Bridge Overhead Crane',NULL,'Capacity: 20 tons, Span: 20m, Lift height: 12m, Speed: 8/2 m/min','Sets','2025-07-14 08:49:59.224279','system',8500),(7,_binary '','TurnTech',NULL,NULL,'Machine Tools','2025-07-14 08:49:59.224279','system','Computer-controlled lathe machine for precision turning operations on large diameter workpieces. Suitable for automotive and aerospace industries.','4500mm x 2200mm x 2000mm','Cast Iron Bed with Steel Components','CL-800','Heavy Duty CNC Lathe',NULL,'Swing over bed: 800mm, Distance between centers: 3000mm, Spindle speed: 2000 RPM, Chuck: 315mm','Pieces','2025-07-14 08:49:59.224279','system',4200),(8,_binary '','HeatPro',NULL,NULL,'Heat Treatment','2025-07-14 08:49:59.239941','system','High-temperature electric furnace for heat treatment, annealing, and tempering of metal components. Programmable temperature control.','2000mm x 1500mm x 1800mm','Refractory Lined Steel Chamber','EHF-1200','Electric Heat Treatment Furnace',NULL,'Max temperature: 1200°C, Chamber: 600x400x400mm, Heating elements: Silicon Carbide, Power: 45kW','Pieces','2025-07-14 08:49:59.239941','system',2800),(9,_binary '','PackTech',NULL,NULL,'Packaging Equipment','20